import type * as CSS from 'csstype';
import type { ReactNode } from 'react';
import type { GroupBase, OptionsOrGroups } from 'react-select';
import type { BehaviorTrackingProps } from '../../core/types/behavior-tracking-props.js';
import { DataTestId } from '../../core/types/data-props.js';
import { StylingProps } from '../../core/types/styling-props.js';
/**
 * @public
 */
export type SelectSingleValue<OptionValue> = OptionValue | null;
/**
 * @public
 */
export type SelectMultiValue<OptionValue> = OptionValue[];
/**
 * @internal
 */
export type SingleOrMultiValue<OptionValue> = SelectMultiValue<OptionValue> | SelectSingleValue<OptionValue>;
/**
 * Internal type for the Option data
 *
 * @internal
 */
export interface BaseOption<OptionValue> extends StylingProps, DataTestId, BehaviorTrackingProps {
    label?: ReactNode;
    value: OptionValue;
    isDisabled?: boolean;
    isSelected?: boolean;
    /**
     * Prefix passed to the option
     */
    prefix: {
        component: ReactNode | null;
        componentProps?: StylingProps & DataTestId & BehaviorTrackingProps;
    };
    /**
     * Suffix passed to the option
     */
    suffix: {
        component: ReactNode | null;
        componentProps?: StylingProps & DataTestId & BehaviorTrackingProps;
    };
    textValue?: string;
    'aria-label'?: string;
}
/**
 * Internal type for Group data
 * @internal
 */
export interface BaseGroup<OptionValue> extends StylingProps, DataTestId, BehaviorTrackingProps {
    label?: string;
    options: BaseOption<OptionValue>[];
    labelProps?: StylingProps & DataTestId & BehaviorTrackingProps;
}
/**
 * Internal type combining either Options or groups
 *
 * @internal
 */
export type OptionOrGroup<OptionValue> = OptionsOrGroups<OptionValue, GroupBase<OptionValue>>;
/**
 * @public
 */
export type SelectTriggerWidthOptionsType = 'content' | 'full' | CSS.Property.Width<string & {}>;
/**
 * @public
 */
export type SelectContentWidthOptionsType = 'trigger' | CSS.Property.Width<string & {}>;
